import android.content.res.Resources
import org.junit.Assert.assertEquals
import org.junit.Assert.assertTrue
import org.junit.Test
import org.junit.runner.RunWith
import org.mockito.Mockito.mock
import androidx.test.ext.junit.runners.AndroidJUnit4

@RunWith(AndroidJUnit4::class)
class HtmlGeneratorTest {

    @Test
    fun testExpandSoundsWithPreferenceEnabled() {
        val generator = HtmlGenerator(
            mock(TypeAnswer::class.java),
            mock(CardAppearance::class.java),
            mock(CardTemplate::class.java),
            mock(Resources::class.java),
            true // showAudioPlayButtons
        )

        val input = "Test [anki:play:q:0]"
        val result = generator.expandSounds(input)

        assertTrue("Result should contain replay button HTML", result.contains("replay-button"))
    }

    @Test
    fun testExpandSoundsWithPreferenceDisabled() {
        val generator = HtmlGenerator(
            mock(TypeAnswer::class.java),
            mock(CardAppearance::class.java),
            mock(CardTemplate::class.java),
            mock(Resources::class.java),
            false // showAudioPlayButtons
        )

        val input = "Test [anki:play:q:0]"
        val result = generator.expandSounds(input)

        assertEquals("Test ", result)
    }
}
"}

